import { Context } from 'hono';

/**
 * Handles the logout request.
 * Invalidates the current session by clearing the session cookie.
 *
 * @param c The Hono context object.
 * @returns A JSON response indicating successful logout.
 */
export async function logoutHandler(c: Context) {
  // Clear the session cookie by setting its Max-Age to 0 and an empty value.
  // Ensure the Path, Domain, HttpOnly, and SameSite attributes match those
  // used when the cookie was originally set to ensure it's correctly cleared.
  // For simplicity, we assume a common path '/' and HttpOnly/SameSite=Lax.
  c.header(
    'Set-Cookie',
    'session_id=; Max-Age=0; Path=/; HttpOnly; SameSite=Lax'
  );

  // In a real application, you would also invalidate the session on the server-side
  // (e.g., delete the session record from a database or cache) using the session ID
  // extracted from the incoming cookie before clearing it.
  // For this exercise, we only focus on the cookie clearing aspect.

  return c.json({ message: 'Logged out successfully' }, 200);
}
